const oldState = msg.data?.old_state?.state ?? null;
const newState = msg.data?.new_state?.state ?? null;

function readConfig(name) {
    return env.get(name) || global.get(name) || null;
}

function mapEventType(previous, current) {
    if (current === 'playing' && previous === 'paused') return 'resume';
    if (current === 'playing') return 'play';
    if (current === 'paused') return 'pause';
    if ((current === 'idle' || current === 'off') && (previous === 'playing' || previous === 'paused')) return 'stop';
    return null;
}

function toInt(value) {
    if (value === null || value === undefined || value === '') return null;
    const parsed = Number(value);
    if (!Number.isFinite(parsed)) return null;
    return Math.max(0, Math.round(parsed));
}

function toPositiveInt(value) {
    const parsed = toInt(value);
    return parsed !== null && parsed > 0 ? parsed : null;
}

function toYear(value) {
    const parsed = toInt(value);
    if (parsed === null || parsed < 1800 || parsed > 3000) return null;
    return parsed;
}

function normalizeMediaContentId(value) {
    if (!value) return null;
    if (typeof value === 'string' || typeof value === 'number') return String(value);
    if (typeof value === 'object') return JSON.stringify(value);
    return null;
}

function extractExternalIds(attrs) {
    const mediaContentId = attrs.media_content_id;
    const ids = typeof mediaContentId === 'object' && mediaContentId !== null ? mediaContentId : {};
    return {
        tmdbId: toInt(attrs.tmdb_id ?? ids.tmdb),
        tvdbId: toInt(attrs.tvdb_id ?? ids.tvdb),
        imdbId: typeof (attrs.imdb_id ?? ids.imdb) === 'string' ? (attrs.imdb_id ?? ids.imdb).trim() || null : null,
        normalizedMediaContentId: normalizeMediaContentId(mediaContentId)
    };
}

function inferMediaType(contentType, season, episode) {
    if (contentType === 'episode' || contentType === 'tvshow') return 'episode';
    if (season !== null && episode !== null) return 'episode';
    return 'movie';
}

function buildMediaSignature(mediaType, title, season, episode, externalIds, attrs) {
    return JSON.stringify({
        mediaType,
        title,
        season,
        episode,
        tmdbId: externalIds.tmdbId,
        tvdbId: externalIds.tvdbId,
        imdbId: externalIds.imdbId,
        mediaContentId: externalIds.normalizedMediaContentId,
        seriesTitle: attrs.media_series_title ?? null
    });
}

function nextSessionKey(signature) {
    const timestamp = Date.now();
    const nonce = Math.random().toString(36).slice(2, 10);
    return `kodi:${timestamp}:${nonce}:${signature}`;
}

const configuredUserId = readConfig('KLUG_USER_ID');
if (!configuredUserId) node.warn('KLUG_USER_ID is not configured');

const eventType = mapEventType(oldState, newState);
if (!eventType) return null;

const stateForMedia = eventType === 'stop' ? (msg.data?.old_state ?? msg.data?.new_state) : (msg.data?.new_state ?? msg.data?.old_state);
const attrs = stateForMedia?.attributes ?? {};

const season = toPositiveInt(attrs.media_season);
const episode = toPositiveInt(attrs.media_episode);
const contentType = String(attrs.media_content_type ?? '').toLowerCase();
const mediaType = inferMediaType(contentType, season, episode);
const title = mediaType === 'episode' ? (attrs.media_series_title || attrs.tvshowtitle || attrs.media_title || attrs.friendly_name) : (attrs.media_title || attrs.friendly_name);
if (!title) return null;

const totalSeconds = toInt(attrs.media_duration);
const watchedSeconds = toInt(attrs.media_position);
const progressPercent = totalSeconds && watchedSeconds !== null ? Number(((Math.min(watchedSeconds, totalSeconds) / totalSeconds) * 100).toFixed(2)) : null;
const externalIds = extractExternalIds(attrs);

const signature = buildMediaSignature(mediaType, title, season, episode, externalIds, attrs);
let sessionKey = flow.get('kodi_session_key');
const existingSignature = flow.get('kodi_media_signature');
if (!sessionKey || existingSignature !== signature || eventType === 'play') sessionKey = nextSessionKey(signature);

flow.set('kodi_session_key', sessionKey);
flow.set('kodi_media_signature', signature);
flow.set('kodi_last_progress_seconds', watchedSeconds);

const currentState = msg.data?.new_state ?? {};
const sourceStamp = currentState.context?.id || currentState.last_updated || currentState.last_changed || Date.now();
msg.payload = {
    user_id: configuredUserId,
    event_type: eventType,
    occurred_at: currentState.last_updated || currentState.last_changed || new Date().toISOString(),
    source_event_id: `kodi:${eventType}:${sourceStamp}`,
    session_key: sessionKey,
    media_type: mediaType,
    title,
    year: toYear(attrs.year),
    season,
    episode,
    tmdb_id: externalIds.tmdbId,
    imdb_id: externalIds.imdbId,
    tvdb_id: externalIds.tvdbId,
    total_seconds: totalSeconds,
    watched_seconds: watchedSeconds,
    progress_percent: progressPercent,
    playback_source: 'kodi',
    payload: {
        entity_id: msg.data?.entity_id ?? 'media_player.kodi',
        old_state: oldState,
        new_state: newState,
        media_title: attrs.media_title ?? null,
        media_series_title: attrs.media_series_title ?? null,
        media_content_id: externalIds.normalizedMediaContentId,
        media_content_type: attrs.media_content_type ?? null,
        app_name: attrs.app_name ?? null
    }
};

if (eventType === 'stop') flow.set('kodi_last_progress_seconds', null);
return msg;

function readConfig(name) {
    return env.get(name) || global.get(name) || null;
}

function toInt(value) {
    if (value === null || value === undefined || value === '') return null;
    const parsed = Number(value);
    if (!Number.isFinite(parsed)) return null;
    return Math.max(0, Math.round(parsed));
}

function toPositiveInt(value) {
    const parsed = toInt(value);
    return parsed !== null && parsed > 0 ? parsed : null;
}

function toYear(value) {
    const parsed = toInt(value);
    if (parsed === null || parsed < 1800 || parsed > 3000) return null;
    return parsed;
}

function normalizeMediaContentId(value) {
    if (!value) return null;
    if (typeof value === 'string' || typeof value === 'number') return String(value);
    if (typeof value === 'object') return JSON.stringify(value);
    return null;
}

function extractExternalIds(attrs) {
    const mediaContentId = attrs.media_content_id;
    const ids = typeof mediaContentId === 'object' && mediaContentId !== null ? mediaContentId : {};
    return {
        tmdbId: toInt(attrs.tmdb_id ?? ids.tmdb),
        tvdbId: toInt(attrs.tvdb_id ?? ids.tvdb),
        imdbId: typeof (attrs.imdb_id ?? ids.imdb) === 'string' ? (attrs.imdb_id ?? ids.imdb).trim() || null : null,
        normalizedMediaContentId: normalizeMediaContentId(mediaContentId)
    };
}

function inferMediaType(contentType, season, episode) {
    if (contentType === 'episode' || contentType === 'tvshow') return 'episode';
    if (season !== null && episode !== null) return 'episode';
    return 'movie';
}

const configuredUserId = readConfig('KLUG_USER_ID');
if (!configuredUserId) node.warn('KLUG_USER_ID is not configured');

const entity = msg.data;
if (!entity || entity.state !== 'playing') return null;

const attrs = entity.attributes ?? {};
const season = toPositiveInt(attrs.media_season);
const episode = toPositiveInt(attrs.media_episode);
const contentType = String(attrs.media_content_type ?? '').toLowerCase();
const mediaType = inferMediaType(contentType, season, episode);
const title = mediaType === 'episode' ? (attrs.media_series_title || attrs.tvshowtitle || attrs.media_title || attrs.friendly_name) : (attrs.media_title || attrs.friendly_name);
if (!title) return null;

const totalSeconds = toInt(attrs.media_duration);
const watchedSeconds = toInt(attrs.media_position);
if (watchedSeconds === null) return null;

const lastProgressSeconds = flow.get('kodi_last_progress_seconds');
if (lastProgressSeconds !== null && lastProgressSeconds !== undefined && watchedSeconds <= lastProgressSeconds) return null;
flow.set('kodi_last_progress_seconds', watchedSeconds);

let sessionKey = flow.get('kodi_session_key');
if (!sessionKey) {
    sessionKey = `kodi:${Date.now()}:progress`;
    flow.set('kodi_session_key', sessionKey);
}

const progressPercent = totalSeconds && watchedSeconds !== null ? Number(((Math.min(watchedSeconds, totalSeconds) / totalSeconds) * 100).toFixed(2)) : null;
const sourceStamp = entity.context?.id || entity.last_updated || entity.last_changed || Date.now();
const externalIds = extractExternalIds(attrs);

msg.payload = {
    user_id: configuredUserId,
    event_type: 'progress',
    occurred_at: entity.last_updated || entity.last_changed || new Date().toISOString(),
    source_event_id: `kodi:progress:${sourceStamp}`,
    session_key: sessionKey,
    media_type: mediaType,
    title,
    year: toYear(attrs.year),
    season,
    episode,
    tmdb_id: externalIds.tmdbId,
    imdb_id: externalIds.imdbId,
    tvdb_id: externalIds.tvdbId,
    total_seconds: totalSeconds,
    watched_seconds: watchedSeconds,
    progress_percent: progressPercent,
    playback_source: 'kodi',
    payload: {
        entity_id: entity.entity_id ?? 'media_player.kodi',
        polled: true,
        state: entity.state,
        media_title: attrs.media_title ?? null,
        media_series_title: attrs.media_series_title ?? null,
        media_content_id: externalIds.normalizedMediaContentId,
        media_content_type: attrs.media_content_type ?? null,
        app_name: attrs.app_name ?? null
    }
};

return msg;

function readConfig(name) {
    return env.get(name) || global.get(name) || null;
}

const baseUrl = readConfig('KLUG_API_BASE_URL');
const apiKey = readConfig('KLUG_API_KEY');
const userId = readConfig('KLUG_USER_ID');

if (!baseUrl) {
    msg.payload = { error: 'KLUG_API_BASE_URL is not set', request: msg.payload };
    return [null, msg];
}

if (!userId) {
    msg.payload = { error: 'KLUG_USER_ID is not set', request: msg.payload };
    return [null, msg];
}

const requestPayload = { ...msg.payload, user_id: userId };
msg.url = new URL('/api/v1/webhooks/kodi/events', baseUrl).toString();
msg.method = 'POST';
msg.headers = {
    'Content-Type': 'application/json'
};
if (apiKey) {
    msg.headers['X-API-Key'] = apiKey;
}
msg.request_payload = requestPayload;
msg.payload = requestPayload;
return [msg, null];

const statusCode = Number(msg.statusCode || 0);
if (statusCode >= 200 && statusCode < 300) return [msg, null];
return [null, msg];
